ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?grade a :Grade .
    ?employee a :Employees .
    ?employee p:hasGrade ?grade .
    ?software_developer a :Software_Developers .
    ?software_developer p:hasEmployee ?employee .
    ?employee p:name ?fullname .
    ?grade p:name ?name_f .
    FILTER(STR(?name_f) = "Senior")
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?grade a :Grade .
    ?employee a :Employees .
    ?employee p:hasGrade ?grade .
    ?data_analyst a :Data_Analysts .
    ?data_analyst p:hasEmployee ?employee .
    ?employee p:name ?fullname .
    ?grade p:name ?name_f .
    FILTER(STR(?name_f) = "Senior")
    BIND(?fullname AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?grade a :Grade .
    ?employee a :Employees .
    ?employee p:hasGrade ?grade .
    ?software_developer a :Software_Developers .
    ?software_developer p:hasEmployee ?employee .
    ?employee p:name ?fullname .
    BIND(?fullname AS ?o0)
  }
  UNION
  {
    ?grade a :Grade .
    ?employee a :Employees .
    ?employee p:hasGrade ?grade .
    ?data_analyst a :Data_Analysts .
    ?data_analyst p:hasEmployee ?employee .
    ?employee p:name ?fullname .
    ?grade p:name ?name_f .
    FILTER(STR(?name_f) = "Senior")
    BIND(?fullname AS ?o0)
  }
} }
}
